SELECT AVG(credit_score) AS average_credit_score
FROM members
WHERE city LIKE 'M%' AND credit_score > 500;

SELECT total_debt 
FROM credit_reports 
WHERE member_id = 'Specific Member ID';

SELECT COUNT(*) as total_members, city, state, zip_code
FROM members
GROUP BY city, state, zip_code;

SELECT member_id
FROM members
WHERE credit_score > 700 AND member_id IN (SELECT member_id FROM loan_payments);

SELECT name 
FROM loan_investors 
WHERE investment_amount > 2500;

SELECT name 
FROM members 
WHERE credit_score = (SELECT MAX(credit_score) FROM members);

SELECT member_id, name, credit_score
FROM members
WHERE credit_score > (SELECT AVG(credit_score) FROM members);

SELECT name, credit_score
FROM members
WHERE credit_score > (
    SELECT AVG(credit_score)
    FROM members
);

SELECT SUM(investment_amount) AS total_active_investment
FROM loan_investors
WHERE investment_status = 'active';

SELECT m.name, m.email, ls.previous_status, ls.new_status
FROM "members" AS m
JOIN "loan_status_history" AS ls ON m.member_id = ls.loan_id;
